import{_ as a,o as t,c as r,aq as i}from"./chunks/framework.Bv06XxhE.js";const p=JSON.parse('{"title":"Effects Kit","description":"","frontmatter":{"title":"Effects Kit"},"headers":[],"relativePath":"handbook/effects-kit.md","filePath":"handbook/effects-kit.md","lastUpdated":1783806877000}'),o={name:"handbook/effects-kit.md"};function n(l,e,s,c,d,h){return t(),r("div",null,[...e[0]||(e[0]=[i('<h1 id="effects-kit" tabindex="-1">Effects Kit <a class="header-anchor" href="#effects-kit" aria-label="Permalink to &quot;Effects Kit&quot;">​</a></h1><blockquote><p>The brand effects kit ported from FIG.07 of the effects kit reference: one law, the ALWAYS / NEVER rules (including the rejected variants), and how each effect maps to a real class or component in <code>@blueprint-chart/ui</code>.</p></blockquote><h2 id="the-law" tabindex="-1">The law <a class="header-anchor" href="#the-law" aria-label="Permalink to &quot;The law&quot;">​</a></h2><p>Ink and light condense around a point of attention. Everything below is that sentence, enforced.</p><h2 id="always" tabindex="-1">ALWAYS <a class="header-anchor" href="#always" aria-label="Permalink to &quot;ALWAYS&quot;">​</a></h2><ul><li>Give every grid pool, grain bloom, and gradient an anchor, a data point, cursor, or CTA.</li><li>On paper, any chartreuse focus dot wears a 2px navy ring, a miniature of the two-circle logo.</li><li>Keep chartreuse at roughly 4% of any composition, it marks decisions and data, nothing else.</li><li>Keep inner card edges crisp; texture lives in the ring and the bloom.</li><li>Use identical grid cell size (20px) and line weight (1px) in both modes.</li><li>Treat gradients on dark as particle-density ramps, two seeds, optical mixing.</li></ul><h2 id="never-including-the-rejected-variants" tabindex="-1">NEVER, including the rejected variants <a class="header-anchor" href="#never-including-the-rejected-variants" aria-label="Permalink to &quot;NEVER, including the rejected variants&quot;">​</a></h2><ul><li>Full-bleed or uniform grid on any surface (rejected: &quot;the clearing&quot;, generic SaaS grid).</li><li>Thin chartreuse strokes or chartreuse text on white.</li><li>Grain on charts, data, text zones, app UI, or any light surface.</li><li>Gradient &quot;drawn line&quot; strokes and sprayed particle shadows (rejected rev 02).</li><li>Visible start/end gaps in perimeter borders (rejected: pen-lift perimeter).</li><li>Stencil overspray borders (rejected).</li><li>Chartreuse in the static logo, nav, or ordinary structure.</li><li>More than one particle ring or one chartreuse CTA per view.</li></ul><h2 id="effects-and-their-classes" tabindex="-1">Effects and their classes <a class="header-anchor" href="#effects-and-their-classes" aria-label="Permalink to &quot;Effects and their classes&quot;">​</a></h2><ul><li><strong>Grid pool</strong> (<code>.bc-pool</code>): the drafting grid revealed radially around an anchor via a mask, never full-bleed; set <code>--bc-pool-x</code> / <code>--bc-pool-y</code> to place it over the anchor.</li><li><strong>Pen &amp; highlighter</strong> (<code>--bc-mark</code>, <code>.bc-highlight</code>): the one marker with two gestures, chartreuse ink on dark, a chartreuse swipe behind body ink on light.</li><li><strong>Grain</strong> (<code>StippleDefs</code>): the shared stipple filter defs, referenced by <code>filter: url(#bc-stipple-a|b|c)</code>; dark marketing surfaces only (the landing hero), never on charts, data, or app UI.</li><li><strong>Particle ring</strong> (<code>BcRing</code>): a stippled gradient stroke framing one featured element per view; inner edges stay crisp, ordinary cards keep flat hairlines instead.</li><li><strong>Buttons</strong> (<code>.btn-bc-primary</code>): the everyday emphasis button, chartreuse fill / navy ink (navy fill / chartreuse ink on light); its hover/focus state is the pooled <code>.bc-pool</code>, not a separate button.</li></ul><h2 id="see-also" tabindex="-1">See also <a class="header-anchor" href="#see-also" aria-label="Permalink to &quot;See also&quot;">​</a></h2><ul><li><a href="/handbook/color">Color &amp; Palettes</a></li><li><a href="/handbook/design-principles">Design Principles</a></li><li><a href="/handbook/anti-patterns">Anti-Patterns</a></li></ul>',12)])])}const u=a(o,[["render",n]]);export{p as __pageData,u as default};
